  ('pukao-e3452428-moex-00135', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依地方制度法規定，關於地方法規之敘述，下列何者正確？', '["山地原住民區代表會之組織自治條例，應報縣政府及行政院原住民委員會核定", "自律規則由各地方立法機關發布，並報各地方行政機關查照", "桃園果菜市場股份有限公司之組織，應由桃園市以地方自治條例定之", "委辦規則應函報受委辦機關核定後發布，其名稱準用自治規則之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
