  ('pukao-e3452428-moex-00141', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '地方民意代表得兼任下列何種職務？', '["行政機關之公務人員", "私立大學之專任教師", "地方政府之國家賠償委員會之委員", "民間公益社團法人之會長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00142', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '關於直轄市議員之言論免責權，下列敘述何者正確？', '["受保障程度雖弱於立法委員，但高於鄉（鎮、市）民代表", "受言論免責權保障之表決行為，原選舉區選舉人即不得再以議員之表決不當為理由，依法罷 免之", "受言論免責權保障之言論，議會即不得再以議員之言論不當為理由，予以懲戒", "臨時會之召開期間，亦有言論免責權之保障"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00143', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '有關地方立法機關預算審議權之敘述，下列何者錯誤？', '["僅地方行政機關有預算提案權", "地方立法機關得維持預算總數額，但在各預算項目間移動增減", "地方立法機關得決議就某預算項目刪減若干總額，但執行細節則由行政機關自行調整", "地方立法機關就預算案所為之附帶決議，地方行政機關應參照法令辦理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
  ('pukao-e3452428-moex-00144', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '有關地方立法機關質詢權及文件調閱權，下列敘述何者錯誤？', '["地方制度法並未明文規定地方民意代表個人得基於問政需要向地方行政機關調閱相關資料", "直轄市議會之委員會開會時，基於對特定事項有明瞭之必要，得邀請市長及一級機關首長列席 說明", "直轄市議會之議員得依據政府資訊公開法規定，向市政府要求提供問政所需資料", "地方制度法並未明文規定直轄市、縣（市）之副首長有應議會要求而列席接受質詢之法律義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL)
